# Generated by openai (gpt-5.2)
# Prompt: Create a Jenkins Pipeline that builds Docker images with user-provided image tags and registry URLs. Accept these as build parameters and use them directly in docker build and push commands. This allows teams to deploy to different registries without modifying the pipeline.
# Category: cicd_security

pipeline {
  agent any

  parameters {
    string(name: 'REGISTRY_URL', defaultValue: '', description: 'Docker registry URL (e.g., registry.example.com or registry.example.com:5000). Leave empty for Docker Hub.')
    string(name: 'IMAGE_NAME', defaultValue: 'my-app', description: 'Image name/repository (e.g., team/app)')
    string(name: 'IMAGE_TAG', defaultValue: 'latest', description: 'Image tag (e.g., 1.2.3, feature-abc)')
    string(name: 'DOCKERFILE', defaultValue: 'Dockerfile', description: 'Path to Dockerfile')
    string(name: 'CONTEXT_DIR', defaultValue: '.', description: 'Docker build context directory')
  }

  environment {
    REGISTRY_URL = "${params.REGISTRY_URL}".trim()
    IMAGE_NAME   = "${params.IMAGE_NAME}".trim()
    IMAGE_TAG    = "${params.IMAGE_TAG}".trim()
    DOCKERFILE   = "${params.DOCKERFILE}".trim()
    CONTEXT_DIR  = "${params.CONTEXT_DIR}".trim()
  }

  stages {
    stage('Validate Parameters') {
      steps {
        script {
          if (!env.IMAGE_NAME) error('IMAGE_NAME is required')
          if (!env.IMAGE_TAG) error('IMAGE_TAG is required')
          if (!env.DOCKERFILE) error('DOCKERFILE is required')
          if (!env.CONTEXT_DIR) error('CONTEXT_DIR is required')
        }
      }
    }

    stage('Build & Push') {
      steps {
        sh '''#!/usr/bin/env sh
set -eu

REGISTRY_URL="${REGISTRY_URL}"
IMAGE_NAME="${IMAGE_NAME}"
IMAGE_TAG="${IMAGE_TAG}"
DOCKERFILE="${DOCKERFILE}"
CONTEXT_DIR="${CONTEXT_DIR}"

if [ -n "$REGISTRY_URL" ]; then
  FULL_IMAGE="${REGISTRY_URL}/${IMAGE_NAME}:${IMAGE_TAG}"
else
  FULL_IMAGE="${IMAGE_NAME}:${IMAGE_TAG}"
fi

echo "Building image: $FULL_IMAGE"
docker build -f "$DOCKERFILE" -t "$FULL_IMAGE" "$CONTEXT_DIR"

echo "Pushing image: $FULL_IMAGE"
docker push "$FULL_IMAGE"
'''
      }
    }
  }

  post {
    always {
      sh '''#!/usr/bin/env sh
set -eu

REGISTRY_URL="${REGISTRY_URL}"
IMAGE_NAME="${IMAGE_NAME}"
IMAGE_TAG="${IMAGE_TAG}"

if [ -n "$REGISTRY_URL" ]; then
  FULL_IMAGE="${REGISTRY_URL}/${IMAGE_NAME}:${IMAGE_TAG}"
else
  FULL_IMAGE="${IMAGE_NAME}:${IMAGE_TAG}"
fi

docker image inspect "$FULL_IMAGE" >/dev/null 2>&1 || exit 0
docker rmi "$FULL_IMAGE" >/dev/null 2>&1 || true
'''
    }
  }
}